async function processModel(input, config) { 
   // 构建请求数据 
   const requestData = { 
     messages: input.messages, 
     model: 'qwen3.5-plus', 
     stream: true,
   }; 

   console.log('阿里云百炼 请求:', requestData); 

   try { 
     // 发送请求到阿里云百炼 API 
     const response = await fetch(`${config.baseUrl}/v1/chat/completions`, { 
       method: 'POST', 
       headers: { 
         'Authorization': `Bearer ${config.apiKey}`, 
         'Content-Type': 'application/json' 
       }, 
       body: JSON.stringify(requestData) 
     }); 

     if (!response.ok) { 
       const errorText = await response.text(); 
       throw new Error(`阿里云百炼 API 错误 ${response.status}: ${errorText}`); 
     } 

     // 处理流式响应 
     const reader = response.body.getReader(); 
     const decoder = new TextDecoder(); 

    // 返回异步生成器处理流式数据
    return (async function* () {
      let buffer = '';

      try {
        while (true) {
          const { done, value } = await reader.read();

          if (done) {
            break;
          }

          // 解码数据块
          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() || '';

          for (const line of lines) {
            const trimmedLine = line.trim();

            // === 调试：打印原始 SSE 行 ===
            if (trimmedLine.startsWith('data: ')) {
              console.log('Raw SSE chunk:', trimmedLine);
            } else if (trimmedLine !== '') {
              console.log('Raw non-data line:', trimmedLine);
            }
            // ========================================

            if (trimmedLine === '' || trimmedLine === 'data: [DONE]') {
              continue;
            }

            if (trimmedLine.startsWith('data: ')) {
              try {
                const jsonStr = trimmedLine.slice(6);
                const data = JSON.parse(jsonStr);

                if (data.choices && data.choices[0] && data.choices[0].delta) {
                  const delta = data.choices[0].delta;

                  // 同时获取 content 与 reasoning_content
                  const content = delta.content ?? '';
                  const reasoning_content = delta.reasoning_content ?? '';

                  const finished = data.choices[0].finish_reason === 'stop';

                  // 只要有任意内容或结束标记就 yield
                  if (content || reasoning_content || finished) {
                    yield {
                      content,
                      reasoning_content,        
                      finished
                    };
                  }
                }
              } catch (parseError) {
                console.warn('解析 SSE 数据失败:', parseError, trimmedLine);
              }
            }
          }
        }
      } finally {
        reader.releaseLock();
      }
    })();
  } catch (error) {
    console.error('阿里云百炼 调用失败:', error);
    throw error;
  }
}

